# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification


import os
import time
import secrets
import hashlib
from datetime import datetime, timedelta
from typing import Optional

from flask import Flask, request, jsonify
from flask_cors import CORS
from web3 import Web3
from eth_account.messages import encode_defunct
import jwt

app = Flask(__name__)
CORS(app)

# Configuration
SECRET_KEY = os.environ.get("JWT_SECRET_KEY", "your-secret-key-change-in-production")
NONCE_EXPIRY_SECONDS = 300  # 5 minutes
JWT_EXPIRY_HOURS = 24

# In-memory stores (use Redis/DB in production)
nonce_store: dict[str, dict] = {}  # address -> {nonce, created_at}
session_store: dict[str, dict] = {}  # address -> {token, created_at, last_active}
revoked_tokens: set[str] = set()

# Initialize Web3
w3 = Web3()


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    random_bytes = secrets.token_bytes(32)
    timestamp = str(time.time()).encode()
    return hashlib.sha256(random_bytes + timestamp).hexdigest()


def create_sign_message(address: str, nonce: str) -> str:
    """Create the message that the user needs to sign."""
    return (
        f"Welcome to Web3 Authentication!\n\n"
        f"Please sign this message to verify your identity.\n\n"
        f"Wallet: {address}\n"
        f"Nonce: {nonce}\n"
        f"Timestamp: {datetime.utcnow().isoformat()}\n\n"
        f"This signature will not trigger a blockchain transaction or cost any gas fees."
    )


def verify_signature(message: str, signature: str, expected_address: str) -> bool:
    """Verify that the signature was created by the expected Ethereum address."""
    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            encoded_message, signature=signature
        )
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def create_jwt_token(address: str) -> str:
    """Create a JWT token for the authenticated user."""
    payload = {
        "sub": address.lower(),
        "iat": datetime.utcnow(),
        "exp": datetime.utcnow() + timedelta(hours=JWT_EXPIRY_HOURS),
        "jti": secrets.token_hex(16),
        "type": "access",
    }
    return jwt.encode(payload, SECRET_KEY, algorithm="HS256")


def decode_jwt_token(token: str) -> Optional[dict]:
    """Decode and validate a JWT token."""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
        if payload.get("jti") in revoked_tokens:
            return None
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def is_valid_eth_address(address: str) -> bool:
    """Check if the given string is a valid Ethereum address."""
    try:
        return Web3.is_address(address) and Web3.is_checksum_address(
            Web3.to_checksum_address(address)
        )
    except Exception:
        return False


def cleanup_expired_nonces():
    """Remove expired nonces from the store."""
    current_time = time.time()
    expired = [
        addr
        for addr, data in nonce_store.items()
        if current_time - data["created_at"] > NONCE_EXPIRY_SECONDS
    ]
    for addr in expired:
        del nonce_store[addr]


def require_auth(f):
    """Decorator to require JWT authentication."""
    from functools import wraps

    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization")
        if not auth_header or not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid authorization header"}), 401

        token = auth_header.split(" ", 1)[1]
        payload = decode_jwt_token(token)
        if not payload:
            return jsonify({"error": "Invalid or expired token"}), 401

        request.user_address = payload["sub"]
        request.token_payload = payload
        return f(*args, **kwargs)

    return decorated


# ==================== API ENDPOINTS ====================


@app.route("/api/auth/nonce", methods=["POST"])
def request_nonce():
    """
    Step 1: Client requests a nonce for their wallet address.
    The nonce is used to create a unique message for signing.
    """
    data = request.get_json()
    if not data or "address" not in data:
        return jsonify({"error": "Wallet address is required"}), 400

    address = data["address"]

    if not is_valid_eth_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    # Cleanup expired nonces periodically
    cleanup_expired_nonces()

    # Generate nonce
    nonce = generate_nonce()
    message = create_sign_message(address, nonce)

    # Store nonce with timestamp
    nonce_store[address.lower()] = {
        "nonce": nonce,
        "message": message,
        "created_at": time.time(),
    }

    return jsonify(
        {
            "success": True,
            "nonce": nonce,
            "message": message,
            "expires_in": NONCE_EXPIRY_SECONDS,
        }
    )


@app.route("/api/auth/verify", methods=["POST"])
def verify_and_authenticate():
    """
    Step 2: Client submits the signed message.
    Server verifies the signature and issues a JWT token.
    """
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body is required"}), 400

    address = data.get("address")
    signature = data.get("signature")
    nonce = data.get("nonce")

    if not all([address, signature, nonce]):
        return jsonify({"error": "Address, signature, and nonce are required"}), 400

    if not is_valid_eth_address(address):
        return jsonify({"error": "Invalid Ethereum address"}), 400

    address_lower = address.lower()

    # Check if nonce exists and is valid
    stored_data = nonce_store.get(address_lower)
    if not stored_data:
        return jsonify({"error": "No pending authentication request. Please request a nonce first."}), 400

    # Check nonce expiry
    if time.time() - stored_data["created_at"] > NONCE_EXPIRY_SECONDS:
        del nonce_store[address_lower]
        return jsonify({"error": "Nonce has expired. Please request a new one."}), 400

    # Verify nonce matches
    if stored_data["nonce"] != nonce:
        return jsonify({"error": "Invalid nonce"}), 400

    # Verify the signature
    message = stored_data["message"]
    if not verify_signature(message, signature, address):
        return jsonify({"error": "Invalid signature. Authentication failed."}), 401

    # Remove used nonce (one-time use)
    del nonce_store[address_lower]

    # Create JWT token
    token = create_jwt_token(address)

    # Store session
    session_store[address_lower] = {
        "token_hash": hashlib.sha256(token.encode()).hexdigest(),
        "created_at": datetime.utcnow().isoformat(),
        "last_active": datetime.utcnow().isoformat(),
    }

    return jsonify(
        {
            "success": True,
            "token": token,
            "address": Web3.to_checksum_address(address),
            "expires_in": JWT_EXPIRY_HOURS * 3600,
            "message": "Authentication successful",
        }
    )


@app.route("/api/auth/refresh", methods=["POST"])
@require_auth
def refresh_token():
    """Refresh an existing valid JWT token."""
    address = request.user_address

    # Revoke old token
    old_jti = request.token_payload.get("jti")
    if old_jti:
        revoked_tokens.add(old_jti)

    # Create new token
    new_token = create_jwt_token(address)

    # Update session
    session_store[address] = {
        "token_hash": hashlib.sha256(new_token.encode()).hexdigest(),
        "created_at": session_store.get(address, {}).get(
            "created_at", datetime.utcnow().isoformat()
        ),
        "last_active": datetime.utcnow().isoformat(),
    }

    return jsonify(
        {
            "success": True,
            "token": new_token,
            "address": Web3.to_checksum_address(address),
            "expires_in": JWT_EXPIRY_HOURS * 3600,
        }
    )


@app.route("/api/auth/logout", methods=["POST"])
@require_auth
def logout():
    """Logout and revoke the current token."""
    address = request.user_address
    jti = request.token_payload.get("jti")

    # Revoke token
    if jti:
        revoked_tokens.add(jti)

    # Remove session
    session_store.pop(address, None)

    return jsonify({"success": True, "message": "Logged out successfully"})


@app.route("/api/auth/me", methods=["GET"])
@require_auth
def get_current_user():
    """Get the currently authenticated user's information."""
    address = request.user_address

    # Update last active
    if address in session_store:
        session_store[address]["last_active"] = datetime.utcnow().isoformat()

    session_info = session_store.get(address, {})

    return jsonify(
        {
            "success": True,
            "user": {
                "address": Web3.to_checksum_address(address),
                "authenticated_at": session_info.get("created_at"),
                "last_active": session_info.get("last_active"),
            },
        }
    )


@app.route("/api/auth/verify-token", methods=["POST"])
def verify_token():
    """Verify if a JWT token is still valid (useful for other services)."""
    data = request.get_json()
    if not data or "token" not in data:
        return jsonify({"error": "Token is required"}), 400

    payload = decode_jwt_token(data["token"])
    if not payload:
        return jsonify({"valid": False, "error": "Invalid or expired token"}), 401

    return jsonify(
        {
            "valid": True,
            "address": Web3.to_checksum_address(payload["sub"]),
            "expires_at": datetime.fromtimestamp(payload["exp"]).isoformat(),
        }
    )


