@app.route("/api/auth/demo", methods=["GET"])
def demo_flow():
    """
    Demonstrates the full authentication flow.
    This endpoint is for development/testing only.
    """
    from eth_account import Account

    # Create a test account
    account = Account.create()
    address = account.address

    # Step 1: Generate nonce
    nonce = generate_nonce()
    message = create_sign_message(address, nonce)

    # Store nonce
    nonce_store[address.lower()] = {
        "nonce": nonce,
        "message": message,
        "created_at": time.time(),
    }

    # Step 2: Sign the message
    encoded_message = encode_defunct(text=message)
    signed = account.sign_message(encoded_message)

    # Step 3: Verify
    is_valid = verify_signature(message, signed.signature.hex(), address)

    # Step 4: Create token if valid
    token = create_jwt_token(address) if is_valid else None

    return jsonify(
        {
            "demo": True,
            "steps": {
                "1_address": address,
                "2_nonce": nonce,
                "3_message": message,
                "4_signature": signed.signature.hex(),
                "5_verification": is_valid,
                "6_token": token,
            },
            "instructions": {
                "step1": "POST /api/auth/nonce with {address: '0x...'}",
                "step2": "Sign the returned message with your wallet (e.g., MetaMask personal_sign)",
                "step3": "POST /api/auth/verify with {address, signature, nonce}",
                "step4": "Use the returned JWT token in Authorization: Bearer <token> header",
                "step5": "GET /api/auth/me to verify your session",
                "step6": "POST /api/auth/logout to end session",
            },
        }
    )


